from collections import deque

def topological_sort(graph: dict[str, list[str]]) -> list[str]:
    """
    graph: adjacency list where graph[u] = [v1, v2, ...] means u -> v1, u -> v2
    Returns a valid execution order, or raises if a cycle is detected.
    """
    in_degree = {node: 0 for node in graph}
    for node in graph:
        for neighbor in graph[node]:
            in_degree[neighbor] = in_degree.get(neighbor, 0) + 1

    # Start with all nodes that have no dependencies
    queue = deque([node for node, deg in in_degree.items() if deg == 0])
    order = []

    while queue:
        node = queue.popleft()
        order.append(node)
        for neighbor in graph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    if len(order) != len(graph):
        raise ValueError("Cycle detected вҖ” not a valid DAG")

    return order

# Example
graph = {
    "extract":  ["clean", "validate"],
    "clean":    ["transform"],
    "validate": ["transform"],
    "transform":["load"],
    "load":     [],
}

print(topological_sort(graph))
# Possible output: ['extract', 'clean', 'validate', 'transform', 'load']

from prefect import flow, task
from prefect.tasks import task_input_hash
from datetime import timedelta

@task(
    retries=3,
    retry_delay_seconds=60,
    cache_key_fn=task_input_hash,      # cache result so reruns skip this task
    cache_expiration=timedelta(hours=1),
)
def extract_data(source: str) -> dict:
    print(f"Extracting from {source}")
    return {"rows": 1000, "source": source}

@task(retries=2)
def clean_data(raw: dict) -> dict:
    return {**raw, "cleaned": True, "nulls_removed": 42}

@task
def validate_data(raw: dict) -> dict:
    assert raw["rows"] > 0, "Empty dataset"
    return {**raw, "valid": True}

@task
def load_data(clean: dict, validated: dict) -> None:
    print(f"Loading: {clean} | validation: {validated}")

@flow(name="etl-pipeline", log_prints=True)
def etl_pipeline(source: str = "api"):
    # Prefect infers dependency from data flow:
    # clean_data and validate_data both depend on extract_data
    # load_data depends on both clean_data and validate_data
    raw = extract_data(source)
    clean = clean_data(raw)
    validated = validate_data(raw)   # runs in parallel with clean_data
    load_data(clean, validated)

if __name__ == "__main__":
    etl_pipeline(source="database")

from dagster import asset, Definitions, define_asset_job

@asset
def raw_data():
    """Extract raw data from source API."""
    return {"rows": 1000, "source": "api"}

@asset
def cleaned_data(raw_data):
    """Clean the raw data вҖ” depends on raw_data."""
    return {**raw_data, "nulls_removed": True}

@asset
def validated_data(raw_data):
    """Validate schema вҖ” depends on raw_data, runs parallel with cleaned_data."""
    assert raw_data["rows"] > 0
    return {**raw_data, "schema_valid": True}

@asset
def warehouse_load(cleaned_data, validated_data):
    """Load to warehouse вҖ” depends on both cleaned and validated."""
    print(f"Loading: {cleaned_data} | {validated_data}")
    return {"status": "loaded"}

etl_job = define_asset_job("etl_job", selection="*")

defs = Definitions(
    assets=[raw_data, cleaned_data, validated_data, warehouse_load],
    jobs=[etl_job],
)

from airflow.decorators import dag, task
from datetime import datetime

@dag(schedule_interval="@daily", start_date=datetime(2024, 1, 1))
def dynamic_pipeline():

    @task
    def get_files() -> list[str]:
        # At runtime, discover how many files need processing
        return ["file_001.csv", "file_002.csv", "file_003.csv"]

    @task
    def process_file(filename: str) -> dict:
        print(f"Processing {filename}")
        return {"file": filename, "rows": 500}

    @task
    def aggregate(results: list[dict]) -> None:
        total = sum(r["rows"] for r in results)
        print(f"Total rows across all files: {total}")

    files = get_files()
    # This creates one task instance per file вҖ” dynamically at runtime
    processed = process_file.expand(filename=files)
    aggregate(processed)

dag = dynamic_pipeline()

